#include "controller.h"

#include <string.h>

static void controller_set_safe_idle(controller_t *controller)
{
    if (controller == NULL) {
        return;
    }

    controller->inlet_open = false;
    controller->heater_on = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_temperature = false;
    controller->previous_temperature_c = 0;
    controller->last_temperature_c = 0;
    controller->last_temperature_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .inlet_open = false,
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };

    if (controller == 0) {
        return output;
    }

    bool previous_inlet_open = controller->inlet_open;
    bool previous_heater_on = controller->heater_on;
    controller_state_t previous_state = controller->state;

    /* Handle timeout and malformed input - go to safe idle */
    if (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT ||
        input.kind == CONTROLLER_INPUT_INVALID_TEMPERATURE ||
        input.kind == CONTROLLER_INPUT_INVALID_LEVEL) {
        controller_set_safe_idle(controller);
        output.inlet_open = controller->inlet_open;
        output.heater_on = controller->heater_on;
        output.state = controller->state;
        output.state_name = controller_state_name(controller->state);
        output.changed = (previous_inlet_open != controller->inlet_open) ||
                         (previous_heater_on != controller->heater_on) ||
                         (previous_state != controller->state);
        return output;
    }

    /* Handle no new input - check for timeout condition */
    if (input.kind == CONTROLLER_INPUT_NONE) {
        /* Check if either sensor has timed out */
        uint32_t now_ms = input.now_ms;

        bool temp_stale = false;
        bool level_stale = false;

        if (controller->has_valid_temperature) {
            if ((now_ms - controller->last_temperature_ms) > CONTROLLER_SENSOR_TIMEOUT_MS) {
                temp_stale = true;
            }
        } else {
            /* No valid temperature yet - not a timeout, just waiting */
        }

        if (controller->has_valid_level) {
            if ((now_ms - controller->last_level_ms) > CONTROLLER_SENSOR_TIMEOUT_MS) {
                level_stale = true;
            }
        } else {
            /* No valid level yet - not a timeout, just waiting */
        }

        /* If either sensor is stale, go to safe idle */
        if (temp_stale || level_stale) {
            controller_set_safe_idle(controller);
            output.inlet_open = controller->inlet_open;
            output.heater_on = controller->heater_on;
            output.state = controller->state;
            output.state_name = controller_state_name(controller->state);
            output.changed = (previous_inlet_open != controller->inlet_open) ||
                             (previous_heater_on != controller->heater_on) ||
                             (previous_state != controller->state);
            return output;
        }

        /* No change - keep current state */
        output.inlet_open = controller->inlet_open;
        output.heater_on = controller->heater_on;
        output.state = controller->state;
        output.state_name = controller_state_name(controller->state);
        return output;
    }

    /* Update sensor freshness based on input type */
    if (input.kind == CONTROLLER_INPUT_TEMPERATURE) {
        controller->has_valid_temperature = true;
        controller->previous_temperature_c = controller->last_temperature_c;
        controller->last_temperature_c = input.temperature_c;
        controller->last_temperature_ms = input.now_ms;
    } else if (input.kind == CONTROLLER_INPUT_LEVEL) {
        controller->has_valid_level = true;
        controller->last_level = input.level;
        controller->last_level_ms = input.now_ms;
    }

    /* Control policy - only act after both sensors are valid */
    bool both_sensors_valid = (controller->has_valid_temperature && controller->has_valid_level);

    if (!both_sensors_valid) {
        /* Stay in safe idle until both sensors are seen */
        output.inlet_open = false;
        output.heater_on = false;
        output.state = CONTROLLER_STATE_SAFE_IDLE;
        output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE);
        output.changed = (previous_inlet_open != false) ||
                         (previous_heater_on != false) ||
                         (previous_state != CONTROLLER_STATE_SAFE_IDLE);
        return output;
    }

    /* Apply control policy */
    int level = controller->last_level;
    int temp = controller->last_temperature_c;
    bool inlet_open_new = false;
    bool heater_on_new = false;
    controller_state_t state_new = CONTROLLER_STATE_SAFE_IDLE;

    /* First check: if LEVEL < 55, heater must always be OFF */
    if (level < 55) {
        inlet_open_new = (level < 60);
        heater_on_new = false;
        if (level < 60) {
            state_new = CONTROLLER_STATE_FILLING;
        } else {
            /* 55 <= LEVEL < 60: filling with heater off */
            state_new = CONTROLLER_STATE_FILLING;
        }
    } else if (level > 75) {
        inlet_open_new = false;
        heater_on_new = false;
        state_new = CONTROLLER_STATE_HOLDING;
    } else {
        /* 55 <= LEVEL <= 75 - apply temperature-based logic */
        if (temp < 45) {
            /* Safe to heat: INLET CLOSED, HEATER ON */
            inlet_open_new = false;
            heater_on_new = true;
            state_new = CONTROLLER_STATE_HEATING;
        } else if (temp >= 45 && temp < 47) {
            /* Inlet closed, hold previous safe heater state */
            inlet_open_new = false;
            heater_on_new = controller->heater_on;
            state_new = CONTROLLER_STATE_HOLDING;
        } else if (temp >= 47 && temp <= 48) {
            /* Check if temperature is rising */
            int prev_temp = controller->previous_temperature_c;
            bool temp_rising = (prev_temp < temp);

            if (temp_rising) {
                /* Early heater off */
                inlet_open_new = false;
                heater_on_new = false;
                state_new = CONTROLLER_STATE_HOLDING;
            } else {
                /* Hold previous safe heater state */
                inlet_open_new = false;
                heater_on_new = controller->heater_on;
                state_new = CONTROLLER_STATE_HOLDING;
            }
        } else if (temp > 48) {
            /* Over temperature: INLET CLOSED, HEATER OFF */
            inlet_open_new = false;
            heater_on_new = false;
            state_new = CONTROLLER_STATE_HOLDING;
        }
    }

    controller->inlet_open = inlet_open_new;
    controller->heater_on = heater_on_new;
    controller->state = state_new;

    output.inlet_open = controller->inlet_open;
    output.heater_on = controller->heater_on;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed = (previous_inlet_open != controller->inlet_open) ||
                     (previous_heater_on != controller->heater_on) ||
                     (previous_state != controller->state);

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILLING:
        return "STATE FILLING";
    case CONTROLLER_STATE_HEATING:
        return "STATE HEATING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_SAFE_IDLE:
    default:
        return "STATE SAFE_IDLE";
    }
}

